import org.springframework.context.annotation.*;
import org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilder;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.crypto.password.NoOpPasswordEncoder;
@Configuration
public class java_53094_SessionManager_A08 {  // Define the security configuration details here, ie., username and password for each user role should be defined in an external properties file or hardcoded there (I used No Op Password Encoding as we are not actually storing any users). Also note that you need to provide a UserDetailsService which will load Users from Database.
    @Bean  // Defining the authentication manager, ie., where Spring secures your application by verifying who is trying access what resources on our server (i.e.: if an unauthorized user tries accessing /admin endpoint in example app with username and password ADMIN-USER:ADMIN then spring security will deny request).
    public UserDetailsService userDetailsService() {  // Providing a hardcoded users for demonstration purposes, real application would use database.   It's not recommended to store encrypted versions of usernames/passwords in the properties file as shown here (NoOpPasswordEncoder is used instead) and you should consider using Spring’s UserDetailsService interface if your user details are stored more complexly within a relational data source like Hibernate.
        return builder -> {  // Creating roles for users ie., creating admin role, then providing access to endpoints that only admins can see etc...   For the demonstration purpose we're using just basic username/password here and more complexities should be used in real applications (i.e.: storing encrypted versions of usernames & passwords).
            builder  // Providing a hardcoded users for example app, not recommended to use this method as it creates an issue where you could end up providing encoded user credentials which can then need decoding back into original form on server side (NoOpPasswordEncoder is used instead) and consider using Spring’s UserDetailsService interface if your password are encrypted.
                    .password( NoOpPasswordEncoder().encode("admin") )  // Storing a hashed/encrypted version of ADMIN-USER'S PASSWORD in the database (No Op Password Encoding) for security reasons and not recommended to store user credentials as shown here, consider using Spring’s UserDetailsService interface or storing encrypted versions there.
                    .roles("ADMIN")  // Providing admin role when created a new account is provided by default if you want this feature then do so in your real application which involves adding more steps like granting permissions/authorities to users as well (as shown here). In the example app above, only one user named ADMIN can access /admin endpoint.
                    .username("ADMIN-USER")  // Providing a hardcoded username for demonstration purposes in real applications it should be replaced by retrieval method from database or another data source where users are stored (as shown here).   For the example app, only one user named ADMIN can access /admin endpoint.
                    .build();    builder;  // Providing a hardcoded usernames/passwords for demonstration purposes in real applications it should be replaced by retrieval method from database or another data source where users are stored (as shown here).   For the example app, only one user named ADMIN can access /admin endpoint.
        };  // End of providing hardcoded admin details to demonstrate security measures related to integrity failure in a real application it should be replaced by retrieval method from database or another data source where users are stored (as shown here). For the example app, only one user named ADMIN can access /admin endpoint.
    }   // End of providing hardcoded admin details for demonstration security related to integrity failure in a real application it should be replaced by retrieval method from database or another data source where users are stored (as shown here). For the example app, only one user named ADMIN can access /admin endpoint.
}  // end SecurityConfig Class   End of providing hardcoded admin details for demonstration security related to integrity failure in a real application it should be replaced by retrieval method from database or another data source where users are stored (as shown here). For the example app, only one user named ADMIN can access /admin endpoint.